refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/three_objects.png"));
gray = image;
mask = gray > 180;
contours = imfindContours(mask, 0, 1);

largestIndex = 1;
largestCount = 0;
for k = 1:length(contours)
    if size(contours(k), 1) > largestCount then
        largestCount = size(contours(k), 1);
        largestIndex = k;
    end
end

points = contours(largestIndex);
result = imellipsefit(points);

t = linspace(0, 2 * %pi, 240)';
majorRadius = result.Axes(1) / 2;
minorRadius = result.Axes(2) / 2;
cosAngle = cos(result.Angle);
sinAngle = sin(result.Angle);
ellipsePoints = [result.Center(1) + majorRadius .* cos(t) .* cosAngle - minorRadius .* sin(t) .* sinAngle, ..
                 result.Center(2) + majorRadius .* cos(t) .* sinAngle + minorRadius .* sin(t) .* cosAngle];

plotContour = rect2cart(size(gray), points);
plotEllipse = rect2cart(size(gray), ellipsePoints);
plotCenter = rect2cart(size(gray), result.Center);

imshow(image);
axesHandle = gca();
axesHandle.auto_clear = "off";
plot(plotContour(:, 1), plotContour(:, 2), "b.");
plot(plotEllipse(:, 1), plotEllipse(:, 2), "r-");
plot(plotCenter(1), plotCenter(2), "g+");
xtitle("Blue: measured contour; red: fitted ellipse; green: center");

disp(result);
